export const PI_EXTENSION_FILES: Record<string, string> = {
  "index.ts": "/**\n * Capability-routing Pi extension (phantombot).\n *\n * Lets a strong-but-narrow PRIMARY Pi model delegate specialist subtasks\n * within a single turn:\n *\n *   look_at_image(path, question) — spawns the IMAGE model to answer a\n *       specific question about an image. Registered ONLY when the primary is\n *       NOT multimodal (the wizard records an `imageModel` in routing.json only\n *       then; for a multimodal primary the key is absent and this tool never\n *       appears — the primary looks at the image itself).\n *\n * This is capability routing WITHIN a turn — orthogonal to phantombot's\n * primary→fallback harness chain (failover), which this extension does not\n * touch.\n *\n * Reads its config from a managed sibling data file `routing.json` in this\n * extension's own directory (see ./tools.ts for the shape). The extension\n * needs zero knowledge of phantombot's config files or env vars.\n *\n * MANAGED SOURCE: this directory is OWNED by phantombot — it is stamped into\n * ~/.pi/agent/extensions/capability-routing/ on every phantombot startup (and\n * repaired by `phantombot doctor`), overwriting any local edits. To change the\n * extension, edit pi-extension/capability-routing/ in the phantombot repo and\n * regenerate the embedded assets (`bun run gen:pi-extension`). A manual symlink\n * (see ./README.md) is only for extension development.\n */\n\nimport type { ExtensionAPI } from \"@earendil-works/pi-coding-agent\";\nimport { Type } from \"typebox\";\nimport * as fs from \"node:fs\";\nimport * as path from \"node:path\";\nimport {\n  imageDelegationPrompt,\n  planRouting,\n  type RoutingConfig,\n} from \"./tools.ts\";\nimport {\n  delegate,\n  delegateFailureText,\n  finalText,\n  isDelegateFailure,\n  usageLine,\n} from \"./spawnPi.ts\";\n\n/**\n * Idle bound for a delegate child (ms): if it produces NO output for this long\n * it's treated as wedged, killed, and returned to the primary as a tested\n * failure (see spawnPi.ts DelegateOptions.idleTimeoutMs).\n *\n * MUST sit comfortably under phantombot's PRIMARY idle watchdog (default 300s),\n * so a wedged delegate returns a tool result BEFORE the primary's own watchdog\n * trips and kills the whole turn — which would (wrongly) look like a primary\n * failure and trigger a harness fallback. 240s leaves ~60s of headroom for the\n * tool to return, the primary to emit its next turn, and iterate.\n */\nconst DELEGATE_IDLE_TIMEOUT_MS = 240_000;\n\n/**\n * The active harness's Pi provider + api-key, relayed from the parent pi via\n * env (PHANTOMBOT_PI_PROVIDER / PHANTOMBOT_PI_API_KEY). The parent harness sets\n * these into THIS process's environment when it spawns us, scoped to whichever\n * pi harness is running this turn — so a box with a primary Pi→OpenRouter and a\n * fallback Pi→OpenAI never collides two providers in one namespace: each pi\n * subtree carries exactly its own pair. We thread them onto the delegate child\n * as `--provider`/`--api-key` flags (see spawnPi.ts) rather than leaning on\n * ambient env, so the bare child can't guess the wrong provider. Blank ⇒\n * undefined (the flag is omitted and Pi uses its own default/local store).\n *\n * The extension is dependency-free and cannot import src/lib/piRouting.ts, so\n * the env-var names are duplicated here as string literals; keep them in sync\n * with ENV_PI_PROVIDER / ENV_PI_API_KEY in src/lib/piRouting.ts.\n */\nfunction piAuthFromEnv(): { provider?: string; apiKey?: string } {\n  const provider = process.env.PHANTOMBOT_PI_PROVIDER?.trim();\n  const apiKey = process.env.PHANTOMBOT_PI_API_KEY?.trim();\n  return {\n    provider: provider ? provider : undefined,\n    apiKey: apiKey ? apiKey : undefined,\n  };\n}\n\n/**\n * Resolve this extension's own directory robustly across runtimes, then read\n * and parse the managed `routing.json` sibling. On ANY error (file missing,\n * unreadable, or invalid JSON) we default to `{}` — which registers no tools,\n * the safe inert state.\n */\nfunction loadRoutingConfig(): RoutingConfig {\n  let dir: string | undefined;\n  // Bun exposes the module dir directly.\n  const bunDir = (import.meta as { dir?: string }).dir;\n  if (typeof bunDir === \"string\" && bunDir.length > 0) {\n    dir = bunDir;\n  } else {\n    try {\n      dir = path.dirname(new URL(import.meta.url).pathname);\n    } catch {\n      dir = undefined;\n    }\n  }\n  if (!dir) return {};\n  try {\n    const raw = fs.readFileSync(path.join(dir, \"routing.json\"), \"utf8\");\n    const parsed = JSON.parse(raw);\n    return parsed && typeof parsed === \"object\" ? (parsed as RoutingConfig) : {};\n  } catch {\n    return {};\n  }\n}\n\nconst LookAtImageParams = Type.Object({\n  path: Type.String({ description: \"Absolute path to the image file to inspect.\" }),\n  question: Type.String({\n    description: \"The specific question to answer about the image (question-driven, not a one-shot describe).\",\n  }),\n});\n\nexport default function (pi: ExtensionAPI) {\n  const plan = planRouting(loadRoutingConfig());\n\n  if (plan.registerLookAtImage && plan.imageModel) {\n    const imageModel = plan.imageModel;\n    pi.registerTool({\n      name: \"look_at_image\",\n      label: \"Look at image\",\n      description: [\n        \"Delegate a vision question to a multimodal image model and get the answer.\",\n        \"ONLY for models that cannot see images themselves: if YOU already accept\",\n        \"image input, do NOT use this tool — read the image directly instead, it is\",\n        \"faster and cheaper. This exists so a text-only model (e.g. a coding model\",\n        \"swapped in for a code turn) still has a way to ask about an image.\",\n        \"Ask a specific question — this is question-driven, not a blind describe.\",\n      ].join(\" \"),\n      parameters: LookAtImageParams,\n      async execute(_id, params, signal) {\n        const { provider, apiKey } = piAuthFromEnv();\n        const r = await delegate({\n          model: imageModel,\n          provider,\n          apiKey,\n          task: imageDelegationPrompt(params.path, params.question),\n          // Vision Q&A doesn't need edit/bash/write; keep it tool-light.\n          tools: [\"read\"],\n          signal,\n          // Bound the delegate so a wedged vision call returns a tested failure\n          // instead of hanging until the primary's own watchdog kills the turn.\n          idleTimeoutMs: DELEGATE_IDLE_TIMEOUT_MS,\n        });\n        if (isDelegateFailure(r)) {\n          return {\n            content: [{ type: \"text\", text: delegateFailureText(\"look_at_image\", r) }],\n            details: { model: imageModel, usage: r.usage },\n            isError: true,\n          };\n        }\n        const answer = finalText(r.messages) || \"(no answer)\";\n        return {\n          content: [{ type: \"text\", text: `${answer}\\n\\n[image model: ${usageLine(r)}]` }],\n          details: { model: imageModel, usage: r.usage },\n        };\n      },\n    });\n  }\n}\n",
  "tools.ts": "/**\n * Pure registration-decision logic for the capability-routing extension.\n *\n * Kept separate from index.ts (the @earendil-works/* glue) so it can be\n * unit-tested from phantombot's `bun test` without the Pi SDK on the import\n * path — the tests import THIS file and assert which tools should register\n * given a routing config object.\n *\n * The config comes from a managed sibling data file `routing.json` that\n * phantombot stamps into the extension directory (see index.ts). Its shape:\n *\n *   {\n *     \"primaryModel\":  \"...\",   // informational; the extension does NOT switch\n *                               //   the primary itself — phantombot's pi harness\n *                               //   passes --model. Surfaced for logging only.\n *     \"imageModel\":    \"...\"    // present ⇒ register look_at_image (vision delegate)\n *   }\n *\n * Every key is optional. The KEY rule: when `imageModel` is absent/empty,\n * `look_at_image` is NOT registered. phantombot now keeps `imageModel` set\n * whenever routing is configured — an explicit pick, or the primary itself when\n * the primary is multimodal — so `look_at_image` is registered even for a\n * vision-capable primary. The tool's DESCRIPTION (see index.ts) tells a model\n * that can already see images not to call it, so a multimodal primary won't,\n * while a text-only coding model swapped in for a code turn still can. Env vars\n * are NOT read by the extension — routing.json is the sole input.\n */\n\nexport interface RoutingConfig {\n  primaryModel?: string;\n  imageModel?: string;\n}\n\nexport interface RoutingPlan {\n  /** Primary model id, if pinned. Informational. */\n  primaryModel?: string;\n  /** Image model id; when present, register look_at_image. */\n  imageModel?: string;\n  /** True when look_at_image should be registered. */\n  registerLookAtImage: boolean;\n}\n\nfunction clean(v: string | undefined): string | undefined {\n  if (v === undefined) return undefined;\n  const t = v.trim();\n  return t.length > 0 ? t : undefined;\n}\n\n/**\n * Decide which routing tools to register from the parsed routing.json config.\n * Each field is normalized (trimmed; blank ⇒ undefined) before deciding.\n */\nexport function planRouting(cfg: RoutingConfig): RoutingPlan {\n  const imageModel = clean(cfg.imageModel);\n  return {\n    primaryModel: clean(cfg.primaryModel),\n    imageModel,\n    registerLookAtImage: imageModel !== undefined,\n  };\n}\n\n/**\n * System prompt for a vision delegation. Question-driven: the parent asks a\n * specific question about an image rather than requesting a one-shot describe,\n * so the answer is scoped to what the orchestrator actually needs.\n */\nexport function imageDelegationPrompt(imagePath: string, question: string): string {\n  return [\n    \"You are a vision specialist answering a single, specific question about an image.\",\n    `Image: ${imagePath}`,\n    `Question: ${question}`,\n    \"\",\n    \"Look at the image and answer the question directly and concisely.\",\n    \"If the image does not contain enough information to answer, say so plainly.\",\n    \"Do not pad the answer with a full description unless the question asks for one.\",\n  ].join(\"\\n\");\n}\n",
  "spawnPi.ts": "/**\n * Spawn a child `pi` process for a delegated subtask and capture its\n * structured JSON output.\n *\n * Mirrors the pattern in pi's own `examples/extensions/subagent/index.ts`:\n *   pi --mode json -p --no-session --model <model> --tools <...> \\\n *      [--append-system-prompt <file>] \"<task>\"\n *\n * Each delegation is a FRESH pi process. That's deliberate: process startup is\n * expensive, so delegations are COARSE-GRAINED — one self-contained chunk, not a\n * chatty back-and-forth. The child gets an isolated context window and reports\n * usage/cost back, which we surface to the parent so cost is visible at the\n * call site.\n */\n\nimport { spawn } from \"node:child_process\";\nimport * as fs from \"node:fs\";\nimport * as os from \"node:os\";\nimport * as path from \"node:path\";\n\n/**\n * Minimal structural shape of pi's assistant `Message`, declared locally\n * instead of imported from `@earendil-works/pi-ai`. This extension is\n * deliberately dependency-free: it is stamped into the host pi's extension\n * directory and runs against whatever `pi-ai` that pi already ships, so the\n * repo does not vendor `pi-ai` — importing its types here would break\n * `tsc --noEmit`. We model only the fields we actually read, defensively, and\n * the JSON we parse off pi's stream is widened into this shape at the boundary.\n *\n * Content parts are a small discriminated union: a `text` part (the only shape\n * we read field-by-field) plus a generic non-text part for tool calls. The\n * non-text discriminant value is nominal — code only ever compares against\n * `\"text\"` — so it never participates in runtime branching.\n */\ninterface MessageUsage {\n  input?: number;\n  output?: number;\n  cacheRead?: number;\n  cacheWrite?: number;\n  cost?: { total?: number };\n  totalTokens?: number;\n}\ntype MessageContentPart =\n  | { type: \"text\"; text: string }\n  | { type: \"toolCall\"; name?: string; toolName?: string; input?: unknown };\nexport interface Message {\n  role: string;\n  content: MessageContentPart[];\n  usage?: MessageUsage;\n  model?: string;\n  stopReason?: string;\n  errorMessage?: string;\n}\n\nexport interface DelegateUsage {\n  input: number;\n  output: number;\n  cacheRead: number;\n  cacheWrite: number;\n  cost: number;\n  contextTokens: number;\n  turns: number;\n}\n\nexport interface DelegateResult {\n  exitCode: number;\n  messages: Message[];\n  stderr: string;\n  usage: DelegateUsage;\n  model?: string;\n  stopReason?: string;\n  errorMessage?: string;\n}\n\nexport interface DelegateOptions {\n  /** Model id to pin via --model (bare name as printed by `pi --list-models`). */\n  model: string;\n  /**\n   * Pi provider for this delegate (e.g. \"openrouter\", \"openai\"), threaded onto\n   * `--provider`. MUST match the api-key's provider: Pi's `--provider` defaults\n   * to google, so an OpenRouter key with no `--provider openrouter` is fired at\n   * the wrong endpoint and auth fails. Sourced from the ACTIVE harness's routing\n   * config (relayed via env by the parent pi), NOT a shared ambient env var —\n   * that's what keeps a primary-Pi→OpenRouter / fallback-Pi→OpenAI box from\n   * colliding two providers in one process namespace. Omit ⇒ no `--provider`\n   * (Pi falls back to its own default, google).\n   */\n  provider?: string;\n  /**\n   * Per-turn Pi api-key, threaded onto `--api-key` exactly like the model is\n   * threaded onto `--model` — never persisted into Pi's own auth store. Omit ⇒\n   * no `--api-key`, and Pi falls back to its own env / local-store settings\n   * (the \"install later, no key\" path). Pairs with `provider` above.\n   */\n  apiKey?: string;\n  /** Comma-list passed to --tools. Omit/empty = pi's default tool set. */\n  tools?: string[];\n  /** Extra system prompt appended via --append-system-prompt (written to a temp file). */\n  systemPrompt?: string;\n  /** The task string (last positional arg). */\n  task: string;\n  /** Working directory for the child. Defaults to the parent's cwd. */\n  cwd?: string;\n  /** Abort signal — propagated as SIGTERM/SIGKILL to the child. */\n  signal?: AbortSignal;\n  /**\n   * Idle timeout (ms). If the child produces NO output (neither stdout nor\n   * stderr) for this long, it is treated as WEDGED: killed (SIGTERM → SIGKILL)\n   * and the call returns with `stopReason: \"timeout\"` instead of hanging.\n   *\n   * This is the TOOL BOUNDARY. A delegate is a tool the primary called, like\n   * bash; when it wedges it must surface as a tested failure the primary can\n   * iterate on — NOT an unbounded hang that starves the primary's own idle\n   * watchdog until the whole turn is killed and (wrongly) treated as a primary\n   * failure. Set this comfortably UNDER the primary's idle window so the tool\n   * returns first. Omit to disable (legacy unbounded behaviour).\n   */\n  idleTimeoutMs?: number;\n  /**\n   * Hard wall-clock cap (ms). Kills the child after this long regardless of\n   * output. Omit to disable (rely on the parent's hard cap). Belt-and-braces\n   * for a child that stays just-chatty-enough to dodge the idle timeout forever.\n   */\n  hardTimeoutMs?: number;\n}\n\n/**\n * Resolve how to re-invoke pi. When the extension runs under a compiled pi\n * single-ELF, `process.execPath` IS pi, so we call it directly. Under a\n * node/bun runtime running pi from source, re-run the same script. Falls back\n * to \"pi\" on PATH. Lifted from the subagent example's getPiInvocation.\n */\nfunction getPiInvocation(args: string[]): { command: string; args: string[] } {\n  const currentScript = process.argv[1];\n  const isBunVirtualScript = currentScript?.startsWith(\"/$bunfs/root/\");\n  if (currentScript && !isBunVirtualScript && fs.existsSync(currentScript)) {\n    return { command: process.execPath, args: [currentScript, ...args] };\n  }\n  const execName = path.basename(process.execPath).toLowerCase();\n  const isGenericRuntime = /^(node|bun)(\\.exe)?$/.test(execName);\n  if (!isGenericRuntime) {\n    return { command: process.execPath, args };\n  }\n  // Bare \"pi\" fallback. On Windows, node's spawn(shell:false) does NOT apply\n  // PATHEXT, so a bare \"pi\" never resolves to the real `pi.cmd`/`pi.exe` shim\n  // and dies with ENOENT (uv_spawn 'pi') — this is exactly the memory/nightly\n  // failure on the Windows port. Resolve the concrete file ourselves so the\n  // spawn stays shell:false (no arg-quoting hazard). No-op on POSIX.\n  return { command: resolveCommandOnPath(\"pi\"), args };\n}\n\n/**\n * Resolve a bare command name to a concrete executable path on Windows using\n * PATH × PATHEXT (the lookup cmd.exe does but node's spawn(shell:false) does\n * not). Returns the input unchanged on POSIX, when already a path, or when\n * nothing matches (so the caller still gets a sensible ENOENT to surface).\n */\nfunction resolveCommandOnPath(cmd: string): string {\n  if (process.platform !== \"win32\") return cmd;\n  if (path.isAbsolute(cmd) || cmd.includes(path.sep) || cmd.includes(\"/\")) return cmd;\n  const exts = (process.env.PATHEXT ?? \".COM;.EXE;.BAT;.CMD\")\n    .split(\";\")\n    .map((e) => e.trim())\n    .filter(Boolean);\n  const dirs = (process.env.PATH ?? process.env.Path ?? \"\").split(path.delimiter);\n  for (const dir of dirs) {\n    if (!dir) continue;\n    // An explicit extension already present? Probe it verbatim first.\n    if (fs.existsSync(path.join(dir, cmd))) return path.join(dir, cmd);\n    for (const ext of exts) {\n      const candidate = path.join(dir, cmd + ext);\n      if (fs.existsSync(candidate)) return candidate;\n    }\n  }\n  return cmd;\n}\n\nfunction emptyUsage(): DelegateUsage {\n  return { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, cost: 0, contextTokens: 0, turns: 0 };\n}\n\n/**\n * Detach a timer from the event loop's ref-count so a pending idle/hard timeout\n * can never keep the process alive on its own. Guards `unref` defensively — the\n * timer handle is typed `number` under some lib configs even though Node's real\n * return value carries `unref()`.\n */\nfunction unrefTimer(t: ReturnType<typeof setTimeout>): void {\n  if (typeof (t as { unref?: () => void }).unref === \"function\") {\n    (t as { unref: () => void }).unref();\n  }\n}\n\n/** Write the appended system prompt to a temp file; pi reads it by path. */\nfunction writePromptTempFile(prompt: string): { dir: string; filePath: string } {\n  const dir = fs.mkdtempSync(path.join(os.tmpdir(), \"phantombot-route-\"));\n  const filePath = path.join(dir, \"system.md\");\n  fs.writeFileSync(filePath, prompt, \"utf-8\");\n  return { dir, filePath };\n}\n\n/** Last assistant text block — the delegate's answer. */\nexport function finalText(messages: Message[]): string {\n  for (let i = messages.length - 1; i >= 0; i--) {\n    const msg = messages[i];\n    if (msg?.role === \"assistant\") {\n      for (const part of msg.content) {\n        if (part.type === \"text\") return part.text;\n      }\n    }\n  }\n  return \"\";\n}\n\n/**\n * Most recent NON-EMPTY assistant text the delegate produced. Unlike\n * `finalText` (which returns the last assistant block even if blank), this\n * skips blank turns so a timeout report can show the last thing the coder\n * actually said before it stalled. Empty string when there's nothing.\n */\nexport function lastProgressText(messages: Message[]): string {\n  for (let i = messages.length - 1; i >= 0; i--) {\n    const msg = messages[i];\n    if (msg?.role === \"assistant\") {\n      for (const part of msg.content) {\n        if (part.type === \"text\" && part.text.trim()) return part.text.trim();\n      }\n    }\n  }\n  return \"\";\n}\n\n/**\n * True when a delegation FAILED: a non-zero exit, or a failure stopReason —\n * `error`, `aborted`, or a `timeout` we imposed at the tool boundary. The tool\n * surfaces these via `delegateFailureText` as an isError result so the primary\n * iterates. A clean `stop`/`toolUse`/undefined stopReason with exit 0 is success.\n */\nexport function isDelegateFailure(r: DelegateResult): boolean {\n  return (\n    r.exitCode !== 0 ||\n    r.stopReason === \"error\" ||\n    r.stopReason === \"aborted\" ||\n    r.stopReason === \"timeout\"\n  );\n}\n\n/**\n * Build the tool-result failure string for a failed/timed-out delegation.\n * Never throws.\n *\n * This is the user-facing half of the TOOL BOUNDARY: a delegate that failed —\n * including a wedge we killed via the idle/hard timeout — returns this string as\n * a normal (isError) tool result so the PRIMARY can read it and iterate, exactly\n * like a non-zero bash exit. On a timeout we also surface the last thing the\n * delegate managed to say and an explicit nudge to retry-or-report, so the\n * primary treats it as a recoverable tool failure rather than a dead end.\n */\nexport function delegateFailureText(kind: string, r: DelegateResult): string {\n  const reason = r.stopReason ?? `exit ${r.exitCode}`;\n  const detail = r.errorMessage || r.stderr.trim() || \"no output\";\n  let text = `${kind} failed (${reason}): ${detail}`;\n  if (r.stopReason === \"timeout\") {\n    const partial = lastProgressText(r.messages);\n    text += partial\n      ? `\\n\\nLast progress before it was stopped: ${clip(partial, 280)}`\n      : `\\n\\nIt produced no usable output before it was stopped.`;\n    text +=\n      `\\n\\nThis is a TOOL failure you can recover from — treat it like a failed ` +\n      `command: refine the task (smaller scope, clearer steps) and call ${kind} ` +\n      `again, or report back what you tried and where it stalled.`;\n  }\n  return text;\n}\n\n/**\n * Build the leading (static) argv for a delegate `pi` invocation: the model,\n * the provider/api-key auth pair, and the optional tool list — everything\n * BEFORE the per-run `--append-system-prompt` and the positional task. Pure and\n * exported so the auth threading is unit-testable without spawning a process.\n *\n * The provider + api-key are threaded as a PAIR, scoped to this delegate's\n * active harness: Pi's `--provider` defaults to google, so a non-google key\n * (e.g. OpenRouter) with no matching `--provider` is fired at the wrong endpoint\n * and auth fails. Either omitted ⇒ its flag is dropped and Pi falls back to its\n * own default / local store for that piece.\n */\nexport function buildDelegateBaseArgs(\n  opts: Pick<DelegateOptions, \"model\" | \"provider\" | \"apiKey\" | \"tools\">,\n): string[] {\n  const args: string[] = [\"--mode\", \"json\", \"-p\", \"--no-session\", \"--model\", opts.model];\n  const provider = opts.provider?.trim();\n  if (provider) args.push(\"--provider\", provider);\n  const apiKey = opts.apiKey?.trim();\n  if (apiKey) args.push(\"--api-key\", apiKey);\n  if (opts.tools && opts.tools.length > 0) args.push(\"--tools\", opts.tools.join(\",\"));\n  return args;\n}\n\nexport async function delegate(opts: DelegateOptions): Promise<DelegateResult> {\n  const args: string[] = buildDelegateBaseArgs(opts);\n\n  const result: DelegateResult = {\n    exitCode: 0,\n    messages: [],\n    stderr: \"\",\n    usage: emptyUsage(),\n    model: opts.model,\n  };\n\n  let tmpDir: string | null = null;\n  let tmpPath: string | null = null;\n  try {\n    if (opts.systemPrompt?.trim()) {\n      const tmp = writePromptTempFile(opts.systemPrompt);\n      tmpDir = tmp.dir;\n      tmpPath = tmp.filePath;\n      args.push(\"--append-system-prompt\", tmpPath);\n    }\n    args.push(opts.task);\n\n    let aborted = false;\n    let timedOut: \"idle\" | \"hard\" | undefined;\n    const exitCode = await new Promise<number>((resolve) => {\n      const inv = getPiInvocation(args);\n      const proc = spawn(inv.command, inv.args, {\n        cwd: opts.cwd,\n        shell: false,\n        stdio: [\"ignore\", \"pipe\", \"pipe\"],\n        // Suppress the console window Windows opens for the delegate pi child.\n        // No-op on POSIX.\n        windowsHide: true,\n      });\n\n      // ── Tool-boundary timeouts ────────────────────────────────────────────\n      // A wedged child must return a tested failure, not hang forever (see\n      // DelegateOptions.idleTimeoutMs). The idle timer resets on ANY raw output\n      // from the child; the hard timer never resets. On expiry we kill the\n      // child and record `timedOut` so the post-await block sets a `timeout`\n      // stopReason the tool surfaces to the primary.\n      let idleTimer: ReturnType<typeof setTimeout> | undefined;\n      let hardTimer: ReturnType<typeof setTimeout> | undefined;\n      const clearTimers = (): void => {\n        if (idleTimer) { clearTimeout(idleTimer); idleTimer = undefined; }\n        if (hardTimer) { clearTimeout(hardTimer); hardTimer = undefined; }\n      };\n      const killTimedOut = (which: \"idle\" | \"hard\"): void => {\n        if (timedOut || aborted) return;\n        timedOut = which;\n        clearTimers();\n        proc.kill(\"SIGTERM\");\n        unrefTimer(setTimeout(() => {\n          if (!proc.killed) proc.kill(\"SIGKILL\");\n        }, 5000));\n      };\n      // Called on every raw chunk from the child (stdout OR stderr) to reset\n      // the idle window — a child that keeps producing output is alive, so the\n      // idle timeout only fires when it goes genuinely silent.\n      const resetIdle = (): void => {\n        if (timedOut || aborted) return;\n        if (opts.idleTimeoutMs !== undefined) {\n          if (idleTimer) clearTimeout(idleTimer);\n          idleTimer = setTimeout(() => killTimedOut(\"idle\"), opts.idleTimeoutMs);\n          unrefTimer(idleTimer);\n        }\n      };\n      if (opts.idleTimeoutMs !== undefined) {\n        idleTimer = setTimeout(() => killTimedOut(\"idle\"), opts.idleTimeoutMs);\n        unrefTimer(idleTimer);\n      }\n      if (opts.hardTimeoutMs !== undefined) {\n        hardTimer = setTimeout(() => killTimedOut(\"hard\"), opts.hardTimeoutMs);\n        unrefTimer(hardTimer);\n      }\n\n      let buffer = \"\";\n      const processLine = (line: string) => {\n        if (!line.trim()) return;\n        let event: { type?: string; message?: Message };\n        try {\n          event = JSON.parse(line);\n        } catch {\n          return;\n        }\n        if (event.type === \"message_end\" && event.message) {\n          const msg = event.message;\n          result.messages.push(msg);\n          if (msg.role === \"assistant\") {\n            result.usage.turns++;\n            const u = msg.usage;\n            if (u) {\n              result.usage.input += u.input || 0;\n              result.usage.output += u.output || 0;\n              result.usage.cacheRead += u.cacheRead || 0;\n              result.usage.cacheWrite += u.cacheWrite || 0;\n              result.usage.cost += u.cost?.total || 0;\n              result.usage.contextTokens = u.totalTokens || 0;\n            }\n            if (!result.model && msg.model) result.model = msg.model;\n            if (msg.stopReason) result.stopReason = msg.stopReason;\n            if (msg.errorMessage) result.errorMessage = msg.errorMessage;\n          }\n        }\n        if (event.type === \"tool_result_end\" && event.message) {\n          result.messages.push(event.message);\n        }\n      };\n\n      proc.stdout.on(\"data\", (data) => {\n        resetIdle();\n        buffer += data.toString();\n        const lines = buffer.split(\"\\n\");\n        buffer = lines.pop() || \"\";\n        for (const line of lines) processLine(line);\n      });\n      proc.stderr.on(\"data\", (data) => {\n        resetIdle();\n        result.stderr += data.toString();\n      });\n      proc.on(\"close\", (code) => {\n        clearTimers();\n        if (buffer.trim()) processLine(buffer);\n        resolve(code ?? 0);\n      });\n      proc.on(\"error\", () => {\n        clearTimers();\n        resolve(1);\n      });\n\n      if (opts.signal) {\n        const kill = () => {\n          aborted = true;\n          proc.kill(\"SIGTERM\");\n          setTimeout(() => {\n            if (!proc.killed) proc.kill(\"SIGKILL\");\n          }, 5000);\n        };\n        if (opts.signal.aborted) kill();\n        else opts.signal.addEventListener(\"abort\", kill, { once: true });\n      }\n    });\n\n    result.exitCode = exitCode;\n    if (aborted) {\n      result.stopReason = \"aborted\";\n      result.errorMessage = \"delegation aborted\";\n    } else if (timedOut) {\n      result.stopReason = \"timeout\";\n      const ms = timedOut === \"idle\" ? opts.idleTimeoutMs! : opts.hardTimeoutMs!;\n      const secs = Math.round(ms / 1000);\n      result.errorMessage =\n        timedOut === \"idle\"\n          ? `no output for ${secs}s (likely wedged on a tool call)`\n          : `exceeded the ${secs}s hard time cap`;\n    }\n    return result;\n  } finally {\n    if (tmpPath) try { fs.unlinkSync(tmpPath); } catch { /* ignore */ }\n    if (tmpDir) try { fs.rmdirSync(tmpDir); } catch { /* ignore */ }\n  }\n}\n\n/** Collapse whitespace and clip to `max` chars with an ellipsis. */\nfunction clip(s: string, max: number): string {\n  const flat = s.replace(/\\s+/g, \" \").trim();\n  return flat.length > max ? flat.slice(0, max - 1).trimEnd() + \"…\" : flat;\n}\n\n/** One-line usage summary for surfacing cost back to the parent model. */\nexport function usageLine(r: DelegateResult): string {\n  const u = r.usage;\n  const parts = [`${u.turns} turn${u.turns === 1 ? \"\" : \"s\"}`];\n  if (u.input) parts.push(`↑${u.input}`);\n  if (u.output) parts.push(`↓${u.output}`);\n  if (u.cost) parts.push(`$${u.cost.toFixed(4)}`);\n  if (r.model) parts.push(r.model);\n  return parts.join(\" \");\n}\n",
  "README.md": "# Capability-routing Pi extension\n\nLets a strong-but-narrow **primary** Pi model delegate a vision subtask\n**within a single turn** to an **image** model. This is *capability routing*,\nwhich is orthogonal to phantombot's primary→fallback harness chain (that's\n*failover* — try the next harness when one dies). The failover chain is\nuntouched by this extension.\n\n## Why\n\nNo single cheap model is great at reasoning **and** vision. Pin a good\norchestrator as the primary and let it hand off a **vision question** to a\nmultimodal image model (`look_at_image`).\n\nCoding is handled separately by phantombot's per-turn **coding-brain swap** (the\npi harness swaps the primary model for the configured coding model on a coding\nturn), not by any tool this extension registers.\n\n## Tools\n\n| Tool | Registered when | What it does |\n|------|-----------------|--------------|\n| `look_at_image(path, question)` | `routing.json` has `imageModel` | Spawns the image model to answer a **specific question** about an image (question-driven, not a one-shot describe). Returns the answer + usage. |\n\n### Always-on image delegate (the key behavior)\n\nphantombot's `harness` wizard keeps an `imageModel` set whenever routing is\nconfigured — an explicit pick, or (when the **primary** is itself vision-capable\nand no pick is made) the **primary model** as the default. So this extension\nregisters `look_at_image` even for a multimodal primary. The tool's\n**description** tells a model that can already see images NOT to call it — so a\nvision primary won't, while a **text-only coding model swapped in for a code\nturn** still has a vision delegate to reach for. `look_at_image` is omitted only\nwhen the operator explicitly picks \"(none)\" for the image model.\n\n## Config: `routing.json` (not env vars)\n\nThe extension reads a single managed data file, `routing.json`, that lives\n**next to this directory's `index.ts`**. phantombot bakes it from `config.toml`'s\n`[harnesses.pi.routing]` table. Shape (every key optional):\n\n```json\n{\n  \"primaryModel\": \"deepseek-v4-pro\",\n  \"imageModel\": \"gpt-4o\"\n}\n```\n\n| Key | Meaning |\n|-----|---------|\n| `primaryModel` | Orchestrator model id (bare name as printed by `pi --list-models`). Informational to the extension — phantombot's pi harness pins it via `--model`. |\n| `imageModel` | Vision delegate. **Set whenever routing is configured** — an explicit pick, or the primary itself when the primary is vision-capable. Absent only when the operator picked \"(none)\" ⇒ `look_at_image` not registered. |\n\nA blank/whitespace value is treated as absent. If `routing.json` is missing or\nunparseable the extension registers **nothing** (the safe inert default).\n\n> **Env vars are no longer used by this extension.** The old\n> `PHANTOMBOT_PRIMARY_MODEL` / `PHANTOMBOT_IMAGE_MODEL` / `PHANTOMBOT_CODING_MODEL`\n> child-env projection has been removed; the wizard still writes those to `~/.env`\n> / `config.toml` as a *config* layer, but the extension reads only `routing.json`.\n\n## Install — automatic\n\nYou do **not** install this by hand. phantombot embeds the extension source in\nits binary and **stamps it into `~/.pi/agent/extensions/capability-routing/` on\nevery startup**, overwriting that owned directory (the same way nginx owns\n`conf.d` or systemd owns its drop-ins). `phantombot doctor` detects a missing or\ndrifted managed extension and re-stamps it. The `routing.json` is written\nalongside the source from your current config.\n\nA manual symlink is only for **extension development** (so `/reload` picks up\nedits to this repo without a rebuild):\n\n```bash\nln -sfn \"$(pwd)/pi-extension/capability-routing\" ~/.pi/agent/extensions/capability-routing\n```\n\nAfter editing the extension source, regenerate the embedded assets so the binary\nships the change: `bun run gen:pi-extension`.\n\n## Files\n\n- `index.ts` — extension entry point; loads `routing.json` from its own dir and registers `look_at_image` per the plan.\n- `tools.ts` — pure registration-decision logic + delegation prompts (unit-tested from phantombot's `bun test`).\n- `spawnPi.ts` — spawns a child `pi --mode json` process and captures structured output (messages, usage, cost, stop reason). Mirrors pi's own subagent example.\n",
};

